const files = Array.isArray($input.first().json) ? $input.first().json : [];
const body = $('Webhook Intake').first().json.body || {};
const rawFormat = String(body.formato || 'carousel').trim();
const format = rawFormat.toLowerCase();
const isPodcast = format === 'podcast';
const prefix = isPodcast ? 'EP' : 'P1';

let maxNum = 0;
for (const file of files) {
  const match = (file.name || '').match(new RegExp('^' + prefix + '_(\\d{3})'));
  if (match) {
    const num = parseInt(match[1], 10);
    if (num > maxNum) maxNum = num;
  }
}

const nextNum = String(maxNum + 1).padStart(3, '0');
const idPieza = prefix + '_' + nextNum;
const year = new Date().getFullYear();
const today = new Date().toISOString().split('T')[0];
const idCompleto = isPodcast ? 'FG-' + year + '-EP_' + nextNum : 'FG-' + year + '-P1_' + nextNum;

const pilares = {
  GD: 'Geopolitik Drop',
  BB: 'Bass & Borders',
  FG: 'Frecuencia Global',
  BP: 'Behind the Policy'
};

const defaultPlatforms = isPodcast ? 'RSS.com, Spotify, Apple Podcasts, YouTube, Website' : 'Instagram';
const defaultDuration = isPodcast ? '18-25 min' : '[por definir]';
const defaultDerivados = isPodcast ? 'Host en RSS.com + videopodcast YouTube largo + 2-3 shorts + X + LinkedIn' : '[por definir]';
const serieEpisodio = isPodcast ? 'Frecuencia Global Podcast - S1E' + nextNum : 'N/A';

function normalizePlatforms(value) {
  if (Array.isArray(value)) return value.join(', ');
  return value || defaultPlatforms;
}

return [{
  json: {
    idPieza,
    idCompleto,
    nextNum,
    titulo: body.titulo,
    pilar: body.pilar,
    pilarNombre: pilares[body.pilar] || body.pilar,
    angulo: body.angulo || '',
    formato: rawFormat || 'carousel',
    plataformas: normalizePlatforms(body.plataformas),
    autor: body.autor || 'Farid Assad',
    deadline: body.deadline || '',
    fecha: today,
    duracion: body.duracion || defaultDuration,
    derivados: body.derivados || defaultDerivados,
    serieEpisodio,
    pieceType: isPodcast ? 'podcast' : 'editorial',
    isPodcast
  }
}];

const template = Buffer.from($json.content, 'base64').toString('utf8');
const data = $('Calcular Siguiente ID').first().json;

const podcastBlock = data.isPodcast
  ? [
      '## PODCAST / VIDEOPODCAST',
      '',
      '| Campo | Valor |',
      '|-------|-------|',
      '| **Tipo de episodio** | [ ] Solo host / [ ] Host + invitados / [ ] Narrado |',
      '| **Salida audio** | [ ] RSS.com / [ ] Spotify / [ ] Apple Podcasts |',
      '| **Salida video** | [ ] YouTube largo / [ ] Shorts derivados |',
      '| **Soporte editorial web** | [ ] Si / [ ] No |',
      '| **Modo de video** | [ ] Visualizer editorial 16:9 / [ ] On-camera / [ ] Hibrido |',
      '| **Show notes requeridas** | [ ] Si / [ ] No |',
      '| **Capitulos / timestamps** | [ ] Si / [ ] No |',
      '| **Deliverables obligatorios** | [audio master, video master 16:9, cover cuadrado, thumbnail 16:9, metadata RSS.com, metadata YouTube, CTA, clip manifest, QA] |',
      '',
      '---',
      ''
    ].join('\n')
  : ['## PODCAST / VIDEOPODCAST', '', '_No aplica para esta pieza._', '', '---', ''].join('\n');

let content = template;
content = content.replace(/\{\{ID_PIEZA\}\}/g, data.idCompleto);
content = content.replace(/\{\{FECHA\}\}/g, data.fecha);
content = content.replace(/\{\{TITULO\}\}/g, data.titulo);
content = content.replace(/\{\{PILAR_MARCADO\}\}/g, data.pilarNombre);
content = content.replace(/\{\{ANGULO\}\}/g, data.angulo);
content = content.replace(/\{\{FORMATO\}\}/g, data.formato);
content = content.replace(/\{\{PLATAFORMAS\}\}/g, data.plataformas);
content = content.replace(/\{\{AUTOR\}\}/g, data.autor);
content = content.replace(/\{\{DEADLINE\}\}/g, data.deadline);
content = content.replace(/\{\{SERIE_EPISODIO\}\}/g, data.serieEpisodio || 'N/A');
content = content.replace(/\{\{DURACION\}\}/g, data.duracion || '[por definir]');
content = content.replace(/\{\{DERIVADOS\}\}/g, data.derivados || '[por definir]');
content = content.replace(/\{\{PODCAST_BLOCK\}\}/g, podcastBlock);

return [{ json: { content, idPieza: data.idPieza, ...data } }];

const data = $input.first().json;
const base64Content = Buffer.from(data.content).toString('base64');
return [{ json: { ...data, base64Content } }];
